args.sparql:
SELECT ?tv_show ?tv_showLabel WHERE {
  ?tv_show wdt:P31 wd:Q11564 .
  ?tv_show wdt:P577 ?start_date .
  FILTER ( ?start_date >= "2010-01-01T00:00:00Z"^^xsd:dateTime && ?start_date <= "2019-12-31T23:59:59Z"^^xsd:dateTime )
  wd:Q23547 wdt:P161 ?tv_show .
  FILTER NOT EXISTS {
    wd:Q23547 p:P161 ?statement .
    ?statement pq:P39 wd:Q225896 .
    ?statement ps:P161 ?tv_show .
  }
  OPTIONAL { ?tv_show rdfs:label ?tv_showLabel . FILTER (lang(?tv_showLabel) = "en") }
}

